{"content":"package ru.samtakoy.network.domain.mapper

class MarketMapper {
    fun toDomain(marketDto: MarketDto): Market {
        if (marketDto.title == null) throw IllegalArgumentException("Title cannot be null")
        return Market(title = marketDto.title, price = marketDto.price)
    }
}
