{"path":"modules/core/core-network/src/commonTest/kotlin/ru/samtakoy/network/domain/mapper/MarketMapperTest.kt","content":"package ru.samtakoy.network.domain.mapper

import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFailsWith
import ru.samtakoy.network.domain.dto.MarketDto
import ru.samtakoy.network.domain.mapper.MarketMapper

class MarketMapperTest {

    @Test
    fun toDomain_withValidMarketDto_mapsFieldsCorrectly() {
        val dto = MarketDto(title = "Test Market", price = 100.0)
        val result = MarketMapper().toDomain(dto)
        assertEquals("Test Market", result.title)
        assertEquals(100.0, result.price)
    }

    @Test
    fun toDomain_withNullTitle_throwsIllegalArgumentException() {
        val dto = MarketDto(title = null, price = 100.0)
        assertFailsWith<IllegalArgumentException> {
            MarketMapper().toDomain(dto)
        }
    }
}"}
